    formData.append(
      "sourcePackage",
      new Blob([zipBuffer], { type: "application/zip" }),
      "source.zip"
    );
    let response;
    try {
      response = await fetch(
        `${API_BASE}/api/skills/${skillId}/versions/submit`,
        {
          method: "POST",
          headers: {
            Cookie: `MINUS_AI_SID=${creds.session_id}`
          },
          body: formData
        }
      );
    } catch (err) {
      return {
        content: [
          { type: "text", text: `\u7F51\u7EDC\u8FDE\u63A5\u5931\u8D25\uFF1A${err.message}` }
        ]
      };
    }
